def total_due(items, tax_rate):
    subtotal = sum(item["price"] * item["quantity"] for item in items)
    if subtotal > 100:
        subtotal = sum(
            item["price"] * item["quantity"] * (0.9 if item.get("category") != "gift_card" else 1)
            for item in items
        )
    return round(subtotal * (1 + tax_rate), 2)
